    public void init()
    {
        next init();

        FormStringControl itemIdControl = this.design().controlName(formControlStr(PurchReqTable, PurchReqLine_ItemId));
        itemIdControl.registerOverrideMethod(methodStr(FormDataObject,lookup),formMethodStr(PurchReqTable,overridenItemIdLookup));
    }

    void setFieldAccess()
    {
        next setFieldAccess();

        PurchReqTable puchReqTable = PurchReqTable_ds.cursor();
        PurchReqLine  purchReqLine = PurchReqLine_ds.cursor();

        boolean allowEdit = purchReqLine ? false : true;

        PurchReqTable_ds.object(fieldNum(PurchReqTable,UBSRecurringServicePurchase)).allowEdit(allowEdit);

        boolean allowEditMandatory = allowEdit && puchReqTable.UBSRecurringServicePurchase == NoYes::Yes;
        
        PurchReqTable_ds.object(fieldNum(PurchReqTable,UBSStartingMonth)).allowEdit(allowEditMandatory);
        PurchReqTable_ds.object(fieldNum(PurchReqTable,UBSStartingMonth)).mandatory(allowEditMandatory);
        PurchReqTable_ds.object(fieldNum(PurchReqTable,UBSPeriodNumber)).allowEdit(allowEditMandatory);
        PurchReqTable_ds.object(fieldNum(PurchReqTable,UBSPeriodNumber)).mandatory(allowEditMandatory);
    }

    /// <summary>
    /// Check if field content is > 0
    /// </summary>
    /// <param name="sender">FormDataObject</param>
    /// <param name="e">FormDataFieldEventArgs</param>
    [FormDataFieldEventHandler(formDataFieldStr(PurchReqTable, PurchReqTable, UBSPeriodNumber), FormDataFieldEventType::Modified)]
    public static void UBSPeriodNumber_OnModified(FormDataObject sender, FormDataFieldEventArgs e)
    {
        FormDataSource  formDataSource = sender.datasource();
        PurchReqTable   purchReqTable  = formDataSource.cursor();

        if(purchReqTable.UBSPeriodNumber <= 0)
        {
            throw Global::error("@UBS:UBSCheckPeriodNumber");
        }
    }

    public void overridenItemIdLookup(FormStringControl _formControl)
    {
        QueryBuildDataSource qbdsErp, qbdsIt;

        PurchReqTable   purchReqTable   = PurchReqTable_ds.cursor(); 
        Query           query           = new Query();

        qbdsErp = query.addDataSource(tableNum(EcoResProduct));
        qbdsIt  = qbdsErp.addDataSource(tableNum(InventTable));
        qbdsIt.joinMode(JoinMode::InnerJoin);
        qbdsIt.relations(false);
        qbdsIt.addLink(fieldNum(EcoResProduct,DisplayProductNumber),fieldNum(InventTable,ItemId));
        
        if(purchReqTable.UBSRecurringServicePurchase)
        {
            qbdsErp.addRange(fieldNum(EcoResProduct, ProductType)).value(queryValue(EcoResProductType::Service));
        }

        SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(EcoResProduct), _formControl);
        sysTableLookup.addLookupfield(fieldNum(EcoResProduct, DisplayProductNumber));
        sysTableLookup.addLookupfield(fieldNum(EcoResProduct, SearchName));
        sysTableLookup.addLookupfield(fieldNum(EcoResProduct, ProductType));
        sysTableLookup.parmQuery(query);
        sysTableLookup.performFormLookup();
    }

    /// <summary>
    /// Auto field the Vendor financial dimension
    /// </summary>
    /// <param name="sender">sender</param>
    /// <param name="e">FormDataFieldEventArgs</param>
    [FormDataFieldEventHandler(formDataFieldStr(PurchReqTable, PurchReqLine, VendAccount), FormDataFieldEventType::Modified)]
    public static void VendAccount_OnModified(FormDataObject sender, FormDataFieldEventArgs e)
    {
        FormDataSource  formDataSource      = sender.datasource();
        PurchReqLine    purchReqLine        = formDataSource.cursor();
        str             dimAttributeName    = DimensionAttribute::UBSGetTableName(tableStr(VendTable),fieldStr(VendTable,AccountNum));

        container conAttribute  = [dimAttributeName];
        container conValue      = [purchReqLine.VendAccount];

        DimensionDefault        newDim    = UBSDefaultDimensionToolKit::createDefaultDimension(conAttribute,conValue);
        LedgerDimensionValueSet mergeDim  = UBSDefaultDimensionToolKit::setDimensionValueToDefaultDimension(purchReqLine.DefaultDimension,newDim,tableStr(VendTable), dimAttributeName);

        purchReqLine.DefaultDimension = mergeDim;
    }

    /// <summary>
    ///
    /// </summary>
    /// <param name="sender"></param>
    /// <param name="e"></param>
    [FormEventHandler(formStr(PurchReqTable), FormEventType::Initialized)]
    public static void PurchReqTable_OnInitialized(xFormRun sender, FormEventArgs e)
    {
        DimensionEntryControl dimControl = sender.design().controlName(identifierStr(LineDimensionEntryControl));
        str dimAttributeName              = DimensionAttribute::UBSGetTableName(tableStr(VendTable),fieldStr(VendTable,AccountNum));
        str dimAttributeProject = 'Project';

        UBSDefaultDimensionToolKit::disableSeveralDimensionsInForm(dimControl, dimAttributeName, dimAttributeProject);
    }

    /// <summary>
    ///
    /// </summary>
    /// <param name="sender"></param>
    /// <param name="e"></param>
    [FormControlEventHandler(formControlStr(PurchReqTable, PurchReqTable_UBSProjectDim), FormControlEventType::Lookup)]
    public static void PurchReqTable_UBSProjectDim_OnLookup(FormControl sender, FormControlEventArgs e)
    {

        UBSProjectDimensionValueLookup::projectDimensionLookup(sender, e);

    }
